function parseCsvLine(line) {
  const fields = [];
  let i = 0;

  while (i <= line.length) {
    if (line[i] === '"') {
      // Quoted field: consume until closing unescaped quote
      let field = '';
      i++; // skip opening quote
      while (i < line.length) {
        if (line[i] === '"') {
          if (line[i + 1] === '"') {
            field += '"';
            i += 2;
          } else {
            i++; // skip closing quote
            break;
          }
        } else {
          field += line[i];
          i++;
        }
      }
      fields.push(field);
      // skip comma separator
      if (line[i] === ',') i++;
    } else {
      // Unquoted field: read up to next comma or end
      const start = i;
      while (i < line.length && line[i] !== ',') i++;
      fields.push(line.slice(start, i));
      // skip comma separator
      if (i < line.length) i++;
      else break;
    }
  }

  return fields;
}

